// GLSL ES 3.0 port
// Changes from HLSL:
// 1. cbuffer -> uniform block (no binding= qualifier in WebGL2)
// 2. float3/float4 -> vec3/vec4
// 3. saturate() -> clamp(x, 0.0, 1.0)
// 4. lerp() -> mix()
// 5. SV_Target -> out vec4 fragColor
// 6. No varyings in this quad renderer — derive pos/normal from gl_FragCoord

uniform vec2 u_resolution;

layout(std140) uniform Light {
    vec3 lightPos;
    float _pad0;
    vec3 lightColor;
    float _pad1;
    vec3 cameraPos;
    float _pad2;
};

out vec4 fragColor;

vec4 blinnPhong(vec3 pos, vec3 normal, vec3 albedo) {
    vec3  L    = normalize(lightPos - pos);
    vec3  V    = normalize(cameraPos - pos);
    vec3  H    = normalize(L + V);
    float diff = clamp(dot(normal, L), 0.0, 1.0);
    float spec = pow(clamp(dot(normal, H), 0.0, 1.0), 32.0);
    vec3  col  = albedo * lightColor * diff + lightColor * spec;
    return vec4(col, 1.0);
}

void main() {
    vec2 uv     = gl_FragCoord.xy / u_resolution;
    vec3 pos    = vec3(uv * 2.0 - 1.0, 0.0);
    vec3 normal = normalize(vec3(uv * 2.0 - 1.0, 1.0));
    vec3 albedo = mix(vec3(0.2, 0.5, 0.9), vec3(0.9, 0.3, 0.1), 0.4);
    fragColor = blinnPhong(pos, normal, albedo);
}

