challenges.description:
The final challenge: port a complete, animated HLSL shader to GLSL ES 3.0. This shader spins the light source and adds a Fresnel-style rim effect. All the skills from this module are needed.

HLSL to port:
```hlsl
cbuffer Uniforms : register(b0) {
    float2 u_resolution;
    float  u_time;
};

float3 rimLight(float3 normal, float3 viewDir, float3 rimColor) {
    float rim = 1.0 - saturate(dot(normal, viewDir));
    return rimColor * pow(rim, 3.0);
}

float4 main(float4 svPos : SV_Position) : SV_Target {
    float2 uv     = svPos.xy / u_resolution;
    float3 pos    = float3(uv * 2.0 - 1.0, 0.0);
    float3 normal = normalize(float3(uv * 2.0 - 1.0, 1.0));
    float3 view   = normalize(float3(0.0, 0.0, 1.0));

    float  angle  = u_time * 1.2;
    float3 light  = normalize(float3(cos(angle), sin(angle), 0.8));
    float3 lColor = lerp(float3(1.0, 0.8, 0.4), float3(0.4, 0.7, 1.0), 0.5 + 0.5 * sin(u_time));

    float  diff   = saturate(dot(normal, light));
    float3 albedo = lerp(float3(0.15, 0.4, 0.8), float3(0.8, 0.2, 0.1), uv.x);
    float3 col    = albedo * lColor * diff;
    col          += rimLight(normal, view, float3(0.3, 0.6, 1.0));
    col           = saturate(col);
    return float4(col, 1.0);
}
```

